(function(w){"use strict";const ID="proportion";function abs(n){return n<0n?-n:n}function gcd(a,b){a=abs(a);b=abs(b);while(b){const t=a%b;a=b;b=t}return a||1n}function parseDec(v){const s=String(v??"").replace(/,/g,"").trim(),m=s.match(/^([+-]?)(\d+)(?:\.(\d+))?$/);if(!m)return null;const f=m[3]||"";let n=BigInt(m[2]+f);if(m[1]==="-")n=-n;let d=10n**BigInt(f.length),g=gcd(n,d);return{n:n/g,d:d/g}}function norm(n,d){if(d<0n){n=-n;d=-d}const g=gcd(n,d);return{n:n/g,d:d/g}}function compute(x){const a=parseDec(x.a),b=parseDec(x.b),c=parseDec(x.c);if(!a||!b||!c)return{error:"A, B, C에 숫자를 입력해 주세요."};if(a.n===0n)return{error:"A는 0이 될 수 없습니다."};const r=norm(b.n*c.n*a.d,b.d*c.d*a.n);const num=Number(r.n),den=Number(r.d),value=num/den;return{numerator:r.n.toString(),denominator:r.d.toString(),fraction:r.d===1n?r.n.toString():r.n.toString()+"/"+r.d.toString(),value:Number.isFinite(value)?value:null}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">A : B = C : X 에서 X를 계산합니다.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-prop-a">A</label><input id="hm-prop-a" class="hm-calc-input" inputmode="decimal" placeholder="예: 2"></div><div class="hm-calc-field"><label for="hm-prop-b">B</label><input id="hm-prop-b" class="hm-calc-input" inputmode="decimal" placeholder="예: 3"></div><div class="hm-calc-field"><label for="hm-prop-c">C</label><input id="hm-prop-c" class="hm-calc-input" inputmode="decimal" placeholder="예: 10"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">X 계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b,c]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:a.value,b:b.value,c:c.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const val=r.value===null?r.fraction:api.formatNumber(r.value,10);api.setResult(res,api.resultCard("X",val,`<dl><dt>정확한 값</dt><dd>${api.escapeHTML(r.fraction)}</dd></dl>`));});reset.addEventListener("click",()=>{a.value=b.value=c.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
